function parseHour(str) {
  const m = (str || '').match(/(\d+)시/);
  return m ? parseInt(m[1], 10) : 0;
}

const DAY_MAP = { '일': 0, '월': 1, '화': 2, '수': 3, '목': 4, '금': 5, '토': 6 };

const now = new Date();
const targetYear = now.getFullYear();
const targetMonth = now.getMonth() + 1;

// 해당 월의 시작일 / 말일
const monthStart = new Date(targetYear, targetMonth - 1, 1);
const monthEnd = new Date(targetYear, targetMonth, 0); // 말일

function toKSTDatetime(date, hour) {
  const yyyy = date.getFullYear();
  const mm = String(date.getMonth() + 1).padStart(2, '0');
  const dd = String(date.getDate()).padStart(2, '0');
  const hh = String(hour).padStart(2, '0');
  return yyyy + '-' + mm + '-' + dd + 'T' + hh + ':00:00+09:00';
}

// 해당 요일의 이번 달 전체 날짜 리스트
function getDatesInMonth(year, month, dow) {
  const dates = [];
  const d = new Date(year, month - 1, 1);
  while (d.getMonth() === month - 1) {
    if (d.getDay() === dow) dates.push(new Date(d));
    d.setDate(d.getDate() + 1);
  }
  return dates;
}

const aggregated = $input.first();
const classList = aggregated.json.data || [];

const records = [];

for (const cls of classList) {
  const props = cls.properties || {};
  const classId = cls.id;

  const 반명 = (props['반명']?.title || []).map(t => t.plain_text).join('');
  const 수업구분Raw = props['수업구분']?.select?.name || '';
  const totalCount = parseInt((수업구분Raw.match(/(\d+)/) || ['0','0'])[1], 10);

  if (totalCount === 0 || !반명) continue;

  const studentIds = (props['Students']?.relation || []).map(r => r.id);

  // 시간표 슬롯: [{day, hour}, ...]
  const slots = [];
  for (let i = 1; i <= 3; i++) {
    const days = (props['수업 ' + i]?.multi_select || []).map(s => s.name);
    const times = (props['시간 ' + i]?.multi_select || []).map(s => s.name);
    for (const day of days) {
      slots.push({ day: day, hour: times.length > 0 ? parseHour(times[0]) : 0 });
    }
  }
  if (slots.length === 0) continue;

  // 슬롯별로 해당 월 전체 날짜 리스튨
  // [{date, hour, slotIdx}, ...] 형도로 전체 나열 후 날짜순 정렬
  const allDates = [];
  for (let si = 0; si < slots.length; si++) {
    const slot = slots[si];
    if (!(slot.day in DAY_MAP)) continue;
    const dates = getDatesInMonth(targetYear, targetMonth, DAY_MAP[slot.day]);
    for (const d of dates) {
      allDates.push({ date: d, hour: slot.hour, slotIdx: si });
    }
  }

  // 날짜순 정렬
  allDates.sort(function(a, b) { return a.date - b.date; });

  // 주차 번호 계산: 요일별 주차 추적
  // ex) 월요일 1주, 2주 / 목요일 1주, 2주
  const dayWeekCount = {}; // dow -> count
  const slotWeekCount = {}; // slotIdx -> count (slot 내 순번)

  // totalCount만큼만 생성
  let seq = 0;
  for (const entry of allDates) {
    if (seq >= totalCount) break;
    seq++;

    const dow = entry.date.getDay();
    dayWeekCount[dow] = (dayWeekCount[dow] || 0) + 1;
    const weekNum = dayWeekCount[dow]; // 해당 요일의 몇 번째 날짜인지
    slotWeekCount[entry.slotIdx] = (slotWeekCount[entry.slotIdx] || 0) + 1;
    const slotInWeek = slotWeekCount[entry.slotIdx]; // 슬롯 내 순번

    records.push({
      json: {
        title: 반명 + ' ' + targetMonth + '월 ' + weekNum + '-' + (entry.slotIdx + 1),
        datetime: toKSTDatetime(entry.date, entry.hour),
        classId: classId,
        studentIds: studentIds,
        반명: 반명,
        seq: seq
      }
    });
  }
}

if (records.length === 0) {
  records.push({ json: { skip: true, message: '생성할 레코드 없음' } });
}

return records;

const candidates = $('Code - 수업일정 계산').all();
const existingItems = $input.all();

// 이번 달 범위
const now = new Date();
const thisYear = now.getFullYear();
const thisMonth = now.getMonth();
const monthStart = new Date(thisYear, thisMonth, 1).getTime();
const monthEnd = new Date(thisYear, thisMonth + 1, 1).getTime();

// 기존 레코드 처리
const existingSet = new Set();
// 반별 최근 과정 추출: classId -> [{date, 과정[]}]
const classLastKajeong = {};

for (const item of existingItems) {
  const props = item.json.properties || {};
  const classId = (props['Class']?.relation || [])[0]?.id || null;
  const dateStr = props['수업일정']?.date?.start || '';
  if (!classId || !dateStr) continue;

  // 이번 달 중복 체크
  const dateTs = new Date(dateStr).getTime();
  if (dateTs >= monthStart && dateTs < monthEnd) {
    existingSet.add(classId + '__' + dateStr.split('T')[0]);
  }

  // 반별 최근 과정 추출 (classId 기준 가장 치는 날짜)
  const 과정Items = props['과정']?.multi_select || [];
  const 과정Names = 과정Items.map(s => s.name);
  if (과정Names.length > 0) {
    if (!classLastKajeong[classId] || dateStr > classLastKajeong[classId].date) {
      classLastKajeong[classId] = { date: dateStr, 과정: 과정Names };
    }
  }
}

// 중복 제외 + 과정 할당
const results = [];
for (const c of candidates) {
  if (c.json.skip) continue;
  const dateOnly = (c.json.datetime || '').split('T')[0];
  const key = c.json.classId + '__' + dateOnly;
  if (!existingSet.has(key)) {
    const lastKajeong = classLastKajeong[c.json.classId];
    results.push({
      json: Object.assign({}, c.json, {
        과정: lastKajeong ? lastKajeong.과정 : []
      })
    });
  }
}

if (results.length === 0) {
  results.push({ json: { skip: true, message: '모두 중복 - 생성 없음' } });
}
return results;

// Aggregate - 생성 목록 합치기 출력에서 읽기
// Aggregate가 빈 경우(신규 생성 0개) 스킵
const aggregateOutput = $input.first();
