if (allCreated.length === 0) {
  return [{ json: { skip: true, message: '생성된 레코드 없음' } }];
}

// classId 기준으로 그룹화
const groups = {};
for (const item of allCreated) {
  const props = item.properties || {};
  const classId = (props['Class']?.relation || [])[0]?.id || 'unknown';
  const dateStr = props['수업일정']?.date?.start || '';
  const pageId = item.id;
  if (!pageId) continue;
  if (!groups[classId]) groups[classId] = [];
  groups[classId].push({ pageId, dateStr });
}

// 각 그룹 날짜순 정렬 후 currentId → nextId 쌍 생성
const pairs = [];
for (const classId of Object.keys(groups)) {
  const items = groups[classId].sort((a, b) => a.dateStr.localeCompare(b.dateStr));
  for (let i = 0; i < items.length - 1; i++) {
    if (items[i].pageId && items[i + 1].pageId) {
      pairs.push({ json: { currentId: items[i].pageId, nextId: items[i + 1].pageId } });
    }
  }
}

if (pairs.length === 0) {
  return [{ json: { skip: true, message: '연결할 쌍 없음' } }];
}

return pairs;

